class Solution {
    public long mostPoints(int[][] questions) {
        int n = questions.length;
        long[] dp = new long[n];
        for (int i = n - 1; i >= 0; i--) {
            if (i + questions[i][1] < n) {
                dp[i] = Math.max(questions[i][0] + dp[i + questions[i][1] + 1], dp[i + 1]);
            } else {
                dp[i] = questions[i][0];
            }
        }
        return dp[0];
    }
}
```

